1	/**
2	 * sessions / session_events / session_reports の DB アクセス層.
3	 */
4	
5	import type Database from "better-sqlite3";
6	import type {
7	  ProviderName,
8	  SessionEventRow,
9	  SessionReportRow,
10	  SessionRow,
11	  SessionStatus,
12	} from "../shared/types.js";
13	
14	export class SessionsRepo {
15	  constructor(private readonly db: Database.Database) {}
16	
17	  // ─── sessions ───────────────────────────────────────
18	
19	  insertSession(input: {
20	    id: string;
21	    provider: ProviderName;
22	    repo_path: string;
23	    repo_origin: string | null;
24	    branch: string | null;
25	    host: string;
26	    started_at: number;
27	    last_seen_at: number;
28	    transcript_path: string | null;
29	    metadata: string | null;
30	  }): void {
31	    this.db
32	      .prepare(
33	        `INSERT INTO sessions(
34	          id, provider, repo_path, repo_origin, branch, host,
35	          started_at, ended_at, status, last_seen_at, current_task,
36	          transcript_path, metadata
37	        ) VALUES (?, ?, ?, ?, ?, ?, ?, NULL, 'active', ?, NULL, ?, ?)`,
38	      )
39	      .run(
40	        input.id,
41	        input.provider,
42	        input.repo_path,
43	        input.repo_origin,
44	        input.branch,
45	        input.host,
46	        input.started_at,
47	        input.last_seen_at,
48	        input.transcript_path,
49	        input.metadata,
50	      );
51	  }
52	
53	  findSession(id: string): SessionRow | null {
54	    return (
55	      (this.db.prepare(`SELECT * FROM sessions WHERE id = ?`).get(id) as SessionRow | undefined) ??
56	      null
57	    );
58	  }
59	
60	  /** 同 repo_path (作業ディレクトリ) の active session 一覧 (引数 id を除外) */
61	  findActivePeers(repoPath: string, excludeId: string): SessionRow[] {
62	    return this.db
63	      .prepare(
64	        `SELECT * FROM sessions WHERE repo_path = ? AND status = 'active' AND id != ?
65	         ORDER BY started_at DESC`,
66	      )
67	      .all(repoPath, excludeId) as SessionRow[];
68	  }
69	
70	  /** 同 (repo_path, host) の lost session 一覧 (resume 候補) */
71	  findLostCandidates(repoPath: string, host: string): SessionRow[] {
72	    return this.db
73	      .prepare(
74	        `SELECT * FROM sessions WHERE repo_path = ? AND host = ? AND status = 'lost'
75	         ORDER BY last_seen_at DESC`,
76	      )
77	      .all(repoPath, host) as SessionRow[];
78	  }
79	
80	  listSessions(filter: {
81	    repo_origin?: string;
82	    host?: string;
83	    status?: SessionStatus;
84	    provider?: ProviderName;
85	  }): SessionRow[] {
86	    const where: string[] = [];
87	    const args: unknown[] = [];
88	    if (filter.repo_origin) { where.push("repo_origin = ?"); args.push(filter.repo_origin); }
89	    if (filter.host)        { where.push("host = ?");        args.push(filter.host); }
90	    if (filter.status)      { where.push("status = ?");      args.push(filter.status); }
91	    if (filter.provider)    { where.push("provider = ?");    args.push(filter.provider); }
92	    const sql =
93	      `SELECT * FROM sessions ${where.length ? "WHERE " + where.join(" AND ") : ""} ` +
94	      `ORDER BY started_at DESC LIMIT 200`;
95	    return this.db.prepare(sql).all(...args) as SessionRow[];
96	  }
97	
98	  updateHeartbeat(id: string, ts: number): void {
99	    this.db.prepare(`UPDATE sessions SET last_seen_at = ? WHERE id = ?`).run(ts, id);
100	  }
101	
102	  patchSession(
103	    id: string,
104	    patch: {
105	      current_task?: string;
106	      branch?: string;
107	      repo_path?: string;
108	      repo_origin?: string | null;
109	    },
110	  ): void {
111	    const sets: string[] = [];
112	    const args: unknown[] = [];
113	    if (patch.current_task !== undefined) { sets.push("current_task = ?"); args.push(patch.current_task); }
114	    if (patch.branch !== undefined)       { sets.push("branch = ?");       args.push(patch.branch); }
115	    if (patch.repo_path !== undefined)    { sets.push("repo_path = ?");    args.push(patch.repo_path); }
116	    if (patch.repo_origin !== undefined)  { sets.push("repo_origin = ?");  args.push(patch.repo_origin); }
117	    if (sets.length === 0) return;
118	    args.push(id);
119	    this.db.prepare(`UPDATE sessions SET ${sets.join(", ")} WHERE id = ?`).run(...args);
120	  }
121	
122	  setMetadata(id: string, metadata: string | null): void {
123	    this.db.prepare(`UPDATE sessions SET metadata = ? WHERE id = ?`).run(metadata, id);
124	  }
125	
126	  /**
127	   * Aggregate distinct hosts with session counts per status. Used by the
128	   * machines API to present a "what's running where" overview.
129	   */
130	  listMachines(): Array<{
131	    host: string;
132	    active: number;
133	    lost: number;
134	    ended: number;
135	    abandoned: number;
136	    last_seen_at: number;
137	  }> {
138	    return this.db
139	      .prepare(
140	        `SELECT host,
141	                SUM(CASE WHEN status = 'active'    THEN 1 ELSE 0 END) AS active,
142	                SUM(CASE WHEN status = 'lost'      THEN 1 ELSE 0 END) AS lost,
143	                SUM(CASE WHEN status = 'ended'     THEN 1 ELSE 0 END) AS ended,
144	                SUM(CASE WHEN status = 'abandoned' THEN 1 ELSE 0 END) AS abandoned,
145	                MAX(last_seen_at) AS last_seen_at
146	           FROM sessions
147	          GROUP BY host
148	          ORDER BY MAX(last_seen_at) DESC`,
149	      )
150	      .all() as Array<{
151	        host: string;
152	        active: number;
153	        lost: number;
154	        ended: number;
155	        abandoned: number;
156	        last_seen_at: number;
157	      }>;
158	  }
159	
160	  /**
161	   * Shallow-merge `partial` into the session's existing metadata blob.
162	   * Keys present in `partial` overwrite; missing keys are preserved.
163	   * `null` value for a key DELETES that key. No-op when session is missing.
164	   *
165	   * Used by Lictor to publish its sidecar port after the pty/sidecar start
166	   * (the initial register happens BEFORE the sidecar is bound, so port is
167	   * not known yet).
168	   */
169	  mergeMetadata(id: string, partial: Record<string, unknown>): void {
170	    const row = this.findSession(id);
171	    if (!row) return;
172	    let current: Record<string, unknown> = {};
173	    if (row.metadata) {
174	      try {
175	        const parsed = JSON.parse(row.metadata) as unknown;
176	        if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
177	          current = parsed as Record<string, unknown>;
178	        }
179	      } catch {
180	        // existing metadata is garbage — treat as empty rather than crash.
181	      }
182	    }
183	    for (const [k, v] of Object.entries(partial)) {
184	      if (v === null) delete current[k];
185	      else current[k] = v;
186	    }
187	    this.setMetadata(id, JSON.stringify(current));
188	  }
189	
190	  countEvents(sessionId: string): number {
191	    const r = this.db
192	      .prepare(`SELECT COUNT(*) AS n FROM session_events WHERE session_id = ?`)
193	      .get(sessionId) as { n: number };
194	    return r.n;
195	  }
196	
197	  /** started_at が [startTs, endTs) の session 集合. day_report 集計用. */
198	  listSessionsInRange(startTs: number, endTs: number): SessionRow[] {
199	    return this.db
200	      .prepare(
201	        `SELECT * FROM sessions WHERE started_at >= ? AND started_at < ? ORDER BY started_at ASC`,
202	      )
203	      .all(startTs, endTs) as SessionRow[];
204	  }
205	
206	  setStatus(id: string, status: SessionStatus, ts: number, endedAt?: number): void {
207	    this.db
208	      .prepare(
209	        `UPDATE sessions SET status = ?, last_seen_at = ?, ended_at = COALESCE(?, ended_at) WHERE id = ?`,
210	      )
211	      .run(status, ts, endedAt ?? null, id);
212	  }
213	
214	  /** active で last_seen_at が cutoff より古いものを返す */
215	  /**
216	   * active かつ last_seen_at が古い session のうち **WS 永続クライアントが繋がっていない** ものだけ返す.
217	   * ws_clients > 0 の session は「作業中」 と見なして lost 化対象から除外する
218	   * (考え事 / build / 入力待ちで hook が静止しても誤 lost を防ぐ).
219	   */
220	  findStaleActive(cutoff: number): SessionRow[] {
221	    return this.db
222	      .prepare(
223	        `SELECT * FROM sessions
224	         WHERE status = 'active' AND last_seen_at < ? AND ws_clients = 0`,
225	      )
226	      .all(cutoff) as SessionRow[];
227	  }
228	
229	  // ─── WS persistent client (active 判定の主軸) ─────────
230	  //
231	  // 接続時に incrementWsClients、 切断時に decrementWsClients を呼ぶ.
232	  // ws_clients > 0 の session は sweeper の lost 判定から除外される.
233	
234	  incrementWsClients(sessionId: string): number {
235	    const now = Math.floor(Date.now() / 1000);
236	    const r = this.db
237	      .prepare(
238	        `UPDATE sessions
239	           SET ws_clients = ws_clients + 1, last_seen_at = ?
240	         WHERE id = ?`,
241	      )
242	      .run(now, sessionId);
243	    if (Number(r.changes ?? 0) === 0) return 0;
244	    const row = this.db
245	      .prepare(`SELECT ws_clients FROM sessions WHERE id = ?`)
246	      .get(sessionId) as { ws_clients: number } | undefined;
247	    return row?.ws_clients ?? 0;
248	  }
249	
250	  decrementWsClients(sessionId: string): number {
251	    const now = Math.floor(Date.now() / 1000);
252	    // 二重減算で負数にならないよう CASE で 0 床を保証.
253	    const r = this.db
254	      .prepare(
255	        `UPDATE sessions
256	           SET ws_clients = CASE WHEN ws_clients > 0 THEN ws_clients - 1 ELSE 0 END,
257	               last_seen_at = ?
258	         WHERE id = ?`,
259	      )
260	      .run(now, sessionId);
261	    if (Number(r.changes ?? 0) === 0) return 0;
262	    const row = this.db
263	      .prepare(`SELECT ws_clients FROM sessions WHERE id = ?`)
264	      .get(sessionId) as { ws_clients: number } | undefined;
265	    return row?.ws_clients ?? 0;
266	  }
267	
268	  /** プロセス再起動時に in-memory の WS 接続が消えた状態を反映するため、 全 session の ws_clients を 0 にリセット. */
269	  resetAllWsClients(): number {
270	    const r = this.db
271	      .prepare(`UPDATE sessions SET ws_clients = 0 WHERE ws_clients > 0`)
272	      .run();
273	    return Number(r.changes ?? 0);
274	  }
275	
276	  /** lost で last_seen_at が cutoff より古いものを abandoned 化 */
277	  abandonLost(cutoff: number): number {
278	    const r = this.db
279	      .prepare(
