1	/**
2	 * Rule Proposer — 固定機能.
3	 *
4	 * 5 分おきに「新しいチャット発言フック rule を提案するか」を AI に問う.
5	 * 既存の rule engine (default-tick) とは独立. tick で chat post する役割と
6	 * 「rule そのものを増やす」役割を分離して、 後者専用の loop を持つ.
7	 *
8	 * 出力 action: add_rule | skip のみ受け付ける. (post / remove は engine 側).
9	 */
10	
11	import type { RulesRepo } from "../db/rules-repo.js";
12	import type { SessionsRepo } from "../db/sessions-repo.js";
13	import type { ChatRepo } from "../db/chat-repo.js";
14	import { runClaude } from "./claude-runner.js";
15	import { handleAction } from "./handler.js";
16	import { createChildLogger } from "../shared/logger.js";
17	
18	const log = createChildLogger("rule-proposer");
19	
20	const DEFAULT_TICK_MS = 5 * 60 * 1000;       // 5 分 (admin で上書き可)
21	const STARTUP_DELAY_MS = 30 * 1000;  // 起動 30 秒後に初回
22	
23	export interface ProposerDeps {
24	  rules: RulesRepo;
25	  sessions: SessionsRepo;
26	  chat: ChatRepo;
27	  /** test 用. true で claude CLI を呼ばずスキップ. */
28	  disable_claude?: boolean;
29	  /** enabled な ai 由来 rule 数がこれ以上なら新規提案を skip (rule 雪だるま防止). */
30	  maxAiRules?: number;
31	  /**
32	   * Runtime kill-switch (AdminState.getRulesEnabled() の否定を期待).
33	   * true で runOnce が claude を呼ばず skip する.
34	   */
35	  rulesDisabled?: () => boolean;
36	  /**
37	   * Tick interval in seconds. Default 300 (5 minutes). Read on each tick
38	   * via this getter so the Web UI can change cadence without restart.
39	   */
40	  intervalSec?: () => number;
41	}
42	
43	export interface ProposerHandle {
44	  stop: () => void;
45	  runOnce: () => Promise<void>;
46	}
47	
48	export function startRuleProposer(deps: ProposerDeps): ProposerHandle {
49	  let timer: NodeJS.Timeout | null = null;
50	  let firstTimer: NodeJS.Timeout | null = null;
51	  let running = false;
52	  let stopped = false;
53	
54	  async function runOnce(): Promise<void> {
55	    if (stopped || running) return;
56	    if (deps.disable_claude || process.env.CONCORDIA_DISABLE_CLAUDE === "1") {
57	      return;
58	    }
59	    if (deps.rulesDisabled?.()) {
60	      // admin が rules-enabled=false にしている. tick は走らせるが claude を呼ばない.
61	      return;
62	    }
63	
64	    running = true;
65	    try {
66	      const enabledRules = deps.rules.list({ enabled: true });
67	
68	      // cap 判定: enabled な AI 由来 rule が上限以上なら claude を呼ばず skip
69	      const cap = deps.maxAiRules;
70	      if (typeof cap === "number" && cap >= 0) {
71	        const aiRuleCount = enabledRules.filter((r) => r.added_by === "ai").length;
72	        if (aiRuleCount >= cap) {
73	          deps.rules.log({
74	            rule_id: null,
75	            action: "skip",
76	            actor: "engine",
77	            detail: `proposer cap reached: ${aiRuleCount}/${cap} ai rules enabled`,
78	          });
79	          log.info({ aiRuleCount, cap }, "rule proposer skipped (cap reached)");
80	          return;
81	        }
82	      }
83	
84	      const recentChat = deps.chat.list({ limit: 30 });
85	      const recentLogs = deps.rules.recentLogs(20);
