});
app.put("/v1/admin/rules-enabled", async (c) => {
  const body = await c.req.json().catch(() => null);
  if (!body || typeof body.enabled !== "boolean") {
    return c.json({ error: "body.enabled (boolean) required" }, 400);
  }
