// セッション一時停止 (paused) 状態の get/put.
app.get("/v1/admin/session/:id/paused", (c) => {
  const id = c.req.param("id");
  const paused = deps.sessions.getPaused(id);
  return c.json({ paused });
});

app.put("/v1/admin/session/:id/paused", async (c) => {
  const id = c.req.param("id");
  const body = await c.req.json().catch(() => null);
  if (!body || typeof body.paused !== "boolean") {
    return c.json({ error: "body.paused (boolean) required" }, 400);
  }
  deps.sessions.setPaused(id, body.paused);
  return c.json({ paused: deps.sessions.getPaused(id) });
});

